INSERT INTO docs (collection, id, json, updatedAt) VALUES ('meta', 'content', '{"updates":[{"version":"0.8.3","note":"Events window widened to next 2 weeks (catches upcoming beginner courses); live feed now honors forBeginners/beginnerFriendly overrides."},{"version":"0.8.2","note":"Lessons restyled as a printed directory: alphabetical, bold names, fine-print contact, hairline separators (no buttons)."},{"version":"0.8.1","note":"Events in 3 tiers: For beginners → A bit more adventurous (beginner-friendly) → Even more (tangotiempo.com)."},{"version":"0.8.0","note":"Live beginner-event feed (next 7 days, forBeginners) from the MasterCalendar API with RRULE expansion; ''more'' → tangotiempo.com."},{"version":"0.7.1","note":"Events reframed to beginner-friendly only (‘ask your buddy’ for more); local /tmp store footgun fixed."},{"version":"0.7.0","note":"/signup (QR target) + /welcome (no-cookie) + smart / router (home vs welcome); footer became a bottom drawer."},{"version":"0.6.0","note":"TangoTiempo event integration: paste a link, auto-pull shortName + organizer + date + venue + icon; live event cards deep-link to TangoTiempo."},{"version":"0.5.4","note":"Slimmed top nav (Be a buddy / Admin / Coming moved to footer-only)."},{"version":"0.5.2","note":"Vercel fix: rename server.js→app.js (avoid magic server-entry hijack)."},{"version":"0.5.1","note":"Vercel deployability fix (static assets, bundled seed, /tmp write fallback)."},{"version":"0.5.0","note":"Lessons tab (real Boston studios) + organizers/teachers model split."},{"version":"0.4.0","note":"Real Boston organizers + TangoTiempo events, More page, Vercel + Firestore-ready (env-gated store)."},{"version":"0.3.0","note":"Token device-landing, thank-you screen, Bring-a-buddy share, social meta/OG + favicon, add-to-home-screen (PWA)."},{"version":"0.2.0","note":"Footer on every page + Updates / Ideas / To-do pages + a mobile-first pass across the whole app + a fresh welcome banner."},{"version":"0.1.1","note":"Events listing, no-login Check-in, Studio handover to a teacher, and Origination (how newcomers found us)."},{"version":"0.1.0","note":"Buddy ↔ Newbie private chat, the Rolling Newbies social feed, and the What''s Coming preview."},{"version":"0.0.x","note":"Newbie capture, Admin hand-match, and the organizers / teachers inventory."}],"ideas":[{"title":"The Buddy Card","note":"One little tango identity that travels with you — from your first lesson to your hundredth milonga, carried in one place."},{"title":"Community network","note":"Weave newcomers, buddies and organizers into one warm, connected Boston tango community."},{"title":"Rolling participation lifecycle","note":"Follow the whole journey — curious newcomer → dancing regular → buddy for the next newcomer — and keep it rolling."},{"title":"Organizer ↔ community chat","note":"A friendly room where hosts and dancers talk directly — ask the locals anything before you even arrive."},{"title":"Multi-city","note":"The same warm on-ramp beyond Boston — a buddy waiting wherever tango is danced."},{"title":"Deeper TangoTiempo connection","note":"Link the community layer to the wider TangoTiempo world so events and people flow together."}],"todos":[{"title":"Token device-landing","note":"A returning visitor''s device remembers them and lands on their events / check-in home instead of the sign-up."},{"title":"Real organizers","note":"Swap the demo placeholders for real Boston teachers and organizers — details coming from Toby."},{"title":"Rolling lifecycle demo","note":"A worked demo of the rolling participation lifecycle end to end."}]}', '2026-07-20T15:56:58.369Z') ON CONFLICT(collection, id) DO UPDATE SET json = excluded.json, updatedAt = excluded.updatedAt;
